import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, Image as ImageIcon, Search, Edit } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminArtworks = () => {
  const [artworks, setArtworks] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllArtworks();
      // FIX: Grab res.data.data from the backend wrapper
      const actualData = res.data?.data || [];
      setArtworks(Array.isArray(actualData) ? actualData : []);
    } catch (err) {
      console.error("Fetch Error:", err);
      setArtworks([]);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const handleDelete = async (id: string) => {
    if (!window.confirm("Delete piece from archive?")) return;
    try {
      await AdminService.deleteArtwork(id);
      toast.success("Piece Removed");
      fetchData();
    } catch (err) { toast.error("Delete Failed"); }
  };

  const filtered = artworks.filter(art => 
    art.Title_In_English?.toLowerCase().includes(search.toLowerCase()) || 
    art.Artwork_ID?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <h1 className="text-4xl font-black uppercase italic text-white">Gallery <span className="text-primary">Artworks</span></h1>
        <Link to="/admin/artworks/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-primary transition-all">
          <Plus size={16} /> Catalog Piece
        </Link>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {filtered.map((art: any) => (
          <div key={art._id} className="bg-[#0f0f0f] rounded-[2rem] overflow-hidden border border-white/5 group">
             <div className="h-56 bg-white/5 flex items-center justify-center overflow-hidden relative">
               <img 
                 src={art.Cloudinary_Image_URL || art.Film_Image_URL || 'https://via.placeholder.com/400x300?text=No+Image'} 
                 className="w-full h-full object-cover transition-transform group-hover:scale-105" 
                 alt="" 
               />
               <div className="absolute top-4 left-4 bg-black/60 px-3 py-1 rounded-lg text-[9px] font-black text-primary">
                 {art.Artwork_ID}
               </div>
             </div>
             <div className="p-6">
               <h4 className="font-black uppercase text-xs italic truncate text-white">{art.Title_In_English || 'Untitled'}</h4>
               <p className="text-[10px] font-bold text-gray-500 mb-4">{art.Artist_Name || art.Artist_ID}</p>
               <div className="flex gap-2">
                 <Link to={`/admin/artworks/edit/${art.Artwork_ID}`} className="flex-1 py-3 bg-white/5 rounded-xl font-black text-[9px] uppercase text-center text-white hover:bg-white hover:text-black">Modify</Link>
                 <button onClick={() => handleDelete(art.Artwork_ID)} className="px-4 py-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                   <Trash2 size={14}/>
                 </button>
               </div>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};
